const MONTH_CODES={jan:'JAN',feb:'FEB',mar:'MAR',apr:'APR',may:'MAY',jun:'JUN',jul:'JUL',aug:'AUG',sep:'SEP',oct:'OCT',nov:'NOV',dec:'DEC',มกราคม:'JAN',กุมภาพันธ์:'FEB',มีนาคม:'MAR',เมษายน:'APR',พฤษภาคม:'MAY',มิถุนายน:'JUN',กรกฎาคม:'JUL',สิงหาคม:'AUG',กันยายน:'SEP',ตุลาคม:'OCT',พฤศจิกายน:'NOV',ธันวาคม:'DEC'};
function inferMonthCode(name){const s=String(name||'').toLowerCase(),direct=s.match(/\b(jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)[-_ ']*(20)?(\d{2})\b/i);if(direct)return MONTH_CODES[direct[1].toLowerCase()]+direct[3];for(const[k,v]of Object.entries(MONTH_CODES)){if(!s.includes(k))continue;const y=s.match(/20(\d{2})|(?:^|\D)(\d{2})(?:\D|$)/);if(y)return v+(y[1]||y[2])}return''}
$('pdf').addEventListener('change',()=>{const code=inferMonthCode($('pdf').files[0]?.name);if(code&&!$('month').value.trim())$('month').value=code});
function validMonth(month){return/^(JAN|FEB|MAR|APR|MAY|JUN|JUL|AUG|SEP|OCT|NOV|DEC)\d{2}$/.test(month)}
function resumeKey(month){const f=sourceFile;return`promo-v2-upload:latest-only-v1:${month}:${f?.name||'unknown'}:${f?.size||0}:${f?.lastModified||0}`}
function loadResume(month){try{return JSON.parse(localStorage.getItem(resumeKey(month))||'null')||{completed:[],attempts:{},updated_at:null}}catch{return{completed:[],attempts:{},updated_at:null}}}
function saveResume(month,state){state.updated_at=new Date().toISOString();localStorage.setItem(resumeKey(month),JSON.stringify(state))}
async function requestJson(payload,key){const r=await fetch(ENDPOINT,{method:'POST',headers:{'Content-Type':'application/json','x-promo-admin-key':key},body:JSON.stringify(payload)}),j=await r.json();if(!r.ok||!j.ok)throw Error((j.error||'request_failed')+(j.detail?': '+JSON.stringify(j.detail):''));return j}
async function postBatch(cards,key,month){const started=performance.now(),j=await requestJson({action:'batch_upload',promo_month_id:month,source_file:sourceFile?.name||'',skip_existing_images:true,function_sync_version:'latest-only-v1',cards:cards.map(it=>({file_name:it.fileName,data_url:it.dataUrl,benefit_text:it.detectedFunctionLabel,detected_function_label:it.detectedFunctionLabel,benefit_confidence:it.ocr.selected?.confidence||0,benefit_box:it.benefitBox,detection_status:it.detectionStatus,detection_method:it.ocr.structuredNew?'structured_new_month_function':'blue_grid_lock_v5_badge_template_two_stage_function_sync'}))},key);return{...j,client_ms:Math.round(performance.now()-started)}}
async function postFinalize(key,month,cards){return requestJson({action:'finalize_latest',promo_month_id:month,confirm_latest_only:true,expected_cards:cards.length,card_ids:cards.map(it=>it.cardId)},key)}
async function postBatchWithRetry(cards,key,month,state,batchNo){let err;for(let attempt=1;attempt<=MAX_BATCH_ATTEMPTS;attempt++){state.attempts[batchNo]=(state.attempts[batchNo]||0)+1;saveResume(month,state);try{return await postBatch(cards,key,month)}catch(e){err=e;log(`Batch ${batchNo+1} ล้มเหลวครั้ง ${attempt}: ${e.message||e}`,'bad');if(attempt<MAX_BATCH_ATTEMPTS)await sleep(600*2**(attempt-1))}}throw err}
async function upload(){const key=$('key').value.trim(),month=$('month').value.trim().toUpperCase();if(!key)return alert('ใส่รหัสก่อน');if(!validMonth(month))return alert('ใส่ Promo Month เช่น AUG26');if(items.length!==212)return alert('ต้องตรวจครบ 212 ใบก่อน');const up=items.filter(x=>x.uploadable);if(up.length!==212)return alert(`ยังมีรายการต้องตรวจ ${212-up.length} ใบ — ระบบจะไม่ลบเดือนปัจจุบัน`);$('upload').disabled=true;const state=loadResume(month),completed=new Set(state.completed),pending=up.filter(x=>!completed.has(x.cardId)),batches=[];for(let i=0;i<pending.length;i+=BATCH_SIZE)batches.push(pending.slice(i,i+BATCH_SIZE));let next=0,done=0,fail=0,syncedFunctions=0,syncedTiers=0,reusedImages=0;const t0=performance.now();await Promise.all(Array.from({length:BATCH_CONCURRENCY},async()=>{while(true){const i=next++;if(i>=batches.length)return;const cards=batches[i];try{const j=await postBatchWithRetry(cards,key,month,state,i);for(const c of cards)completed.add(c.cardId);state.completed=[...completed];saveResume(month,state);syncedFunctions+=Number(j.functions_synced||0);syncedTiers+=Number(j.tiers_synced||0);reusedImages+=Number(j.images_reused||0);log(`✓ Batch ${i+1}/${batches.length}: ฟังก์ชัน ${j.functions_synced||0} | ขั้นโปร ${j.tiers_synced||0} | ใช้รูปเดิม ${j.images_reused||0} | retry ${state.attempts[i]-1}`,'ok')}catch(e){fail+=cards.length;log(`✗ Batch ${i+1} ค้าง ${cards.length} ใบ: ${e.message||e}`,'bad')}done++;bar(done,Math.max(1,batches.length))}}));if(fail||completed.size!==212){st(`อัปโหลดไม่ครบ ${completed.size}/212 — ยังไม่เปลี่ยนเดือนและไม่ลบข้อมูลเก่า`);$('upload').disabled=false;return}try{st('ตรวจครบแล้ว กำลังตั้งเป็นเดือนล่าสุดและลบเดือนเก่า...');const j=await postFinalize(key,month,up);localStorage.removeItem(resumeKey(month));log(`✓ เผยแพร่ ${j.current_month} แล้ว | ลบเดือนเก่า ${(j.old_months_deleted||[]).join(', ')||'ไม่มี'} | ลบไฟล์ ${j.files_deleted||0}`,'ok');st(`สำเร็จ: ${month} เป็นเดือนล่าสุด | ตรวจ ${j.validated_cards}/212 | ลบไฟล์เก่า ${j.files_deleted||0} | ${((performance.now()-t0)/1000).toFixed(1)} วินาที`)}catch(e){log(`✗ ยังไม่สลับเดือน: ${e.message||e}`,'bad');st('อัปโหลดครบแต่ตรวจขั้นสุดท้ายไม่ผ่าน — เดือนเก่ายังไม่ถูกลบ')}finally{$('upload').disabled=false}}
